import clsx from 'clsx';
import { type ReactNode, forwardRef } from 'react';

import { FormFieldMessageItem } from './FormFieldMessageItem.js';
import * as styles from './FormFieldMessages.sty.js';
import { useBehavioralTrackingProps } from '../../../../core/hooks/useBehavioralTrackingProps.js';
import type { BehaviorTrackingProps } from '../../../../core/types/behavior-tracking-props.js';
import type { DataTestId } from '../../../../core/types/data-props.js';
import type { MaskingProps } from '../../../../core/types/masking-props.js';
import type { StylingProps } from '../../../../core/types/styling-props.js';
import { Flex } from '../../../../layouts/flex/Flex.js';
import { useFormFieldContext } from '../../hooks/useFormFieldContext.js';
import { useFormFieldMessagesContext } from '../../hooks/useFormFieldMessagesContext.js';
import type { FormFieldControlMessage } from '../../types/formfield-messages.types.js';

/**
 * Properties for the FormFieldMessages component.
 * @public
 */
export type FormFieldMessageProps = MaskingProps &
  StylingProps &
  DataTestId &
  BehaviorTrackingProps & {
    children?:
      | ((messages: FormFieldControlMessage[]) => ReactNode[] | ReactNode)
      | ReactNode;
  };

/**
 * Component to display FormFieldMessages coming from the form control.
 */
const FormFieldMessagesRoot = /* @__PURE__ */ forwardRef<
  HTMLDivElement,
  FormFieldMessageProps
>((FormFieldMessageProps, forwardedRef) => {
  const {
    children,
    className: consumerClassName,
    style: consumerStyle,
    'data-dtrum-allow': dataDtrumAllow,
    'data-dtrum-mask': dataDtrumMask,
    'data-testid': dataTestId,
    ...remainingProps
  } = FormFieldMessageProps;

  const [behavioralTrackingProps] = useBehavioralTrackingProps(remainingProps);

  const { state } = useFormFieldMessagesContext();
  const { disabled, ariaDisabled } = useFormFieldContext();

  const errorMessages = state.formControlMessages.filter(
    (message) => message.variant === 'error',
  );
  const internalHintMessages = state.formControlMessages.filter(
    (message) => message.variant === 'hint',
  );

  const externalHintMessages = state.customMessages.filter(
    (message) => message.variant === 'hint',
  );

  const hintMessages = [...internalHintMessages, ...externalHintMessages];
  const formMessages = state.showError ? errorMessages : internalHintMessages;

  const hideMessages = !state.showError && hintMessages.length === 0;

  // if there is a render function we use this, otherwise we render children if any are provided
  // if no children are provided, we render all form control messages
  let content: ReactNode[] | ReactNode = null;
  if (typeof children === 'function') {
    content = children(formMessages);
  } else if (children !== undefined && children !== null) {
    content = children;
  } else {
    content = formMessages.map((message) => (
      <FormFieldMessages.Item
        disabled={disabled || ariaDisabled}
        {...message}
        key={message.id}
      />
    ));
  }

  // if there is a render function we use this, otherwise we render children if any are provided
  // if no children are provided we render all form control messages
  return (
    <Flex
      ref={forwardedRef}
      flexDirection="column"
      aria-live="polite"
      /**
       * We always need to render the FormFieldMessageItems so that they can register in the context and update the form state correctly.
       * However, we only want to display them when they are a hint or if showError is true.
       */
      style={{ ...consumerStyle, display: hideMessages ? 'none' : 'flex' }}
      className={clsx(consumerClassName, styles.formFieldMessages)}
      aria-hidden={hideMessages}
      data-dtrum-allow={dataDtrumAllow}
      data-dtrum-mask={dataDtrumMask}
      data-testid={dataTestId}
      {...behavioralTrackingProps}
    >
      {content}
    </Flex>
  );
});

(
  FormFieldMessagesRoot as typeof FormFieldMessagesRoot & {
    displayName: string;
  }
).displayName = 'FormFieldMessages';

/**
 * @public
 */
export const FormFieldMessages = Object.assign(FormFieldMessagesRoot, {
  Item: FormFieldMessageItem,
});
